import{_ as t,o as l,c as a,a2 as d}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"缩放器参考","description":"","frontmatter":{},"headers":[],"relativePath":"zh/scalers/reference.md","filePath":"zh/scalers/reference.md"}'),r={name:"zh/scalers/reference.md"};function o(n,e,i,s,c,g){return l(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="缩放器参考" tabindex="-1"><i class="ph ph-sliders"></i> 缩放器参考 <a class="header-anchor" href="#缩放器参考" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-sliders&quot;&gt;&lt;/i&gt; 缩放器参考&quot;">​</a></h1><p>Web Adaptive Performance 包含一套专门的缩放器 (Scalers)（优化模块）。索引器自动根据其 <code>Visual Impact</code> 和当前的瓶颈类型（<code>Target</code>: CPU 或 GPU）选择要部署的缩放器。</p><h2 id="兼容性矩阵" tabindex="-1">兼容性矩阵 <a class="header-anchor" href="#兼容性矩阵" aria-label="Permalink to &quot;兼容性矩阵&quot;">​</a></h2><p>以下是所有可用模块的兼容性矩阵和说明。</p><table tabindex="0"><thead><tr><th style="text-align:left;">缩放器</th><th style="text-align:left;">管线</th><th style="text-align:left;">目标</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Resolution</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">降低渲染分辨率，从根本上减少 GPU 填充率 (Fillrate) 的负载。<em>详细信息请见下文。</em></td></tr><tr><td style="text-align:left;"><strong>Shadows Quality</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">分阶段禁用阴影。<br>在 <strong>URP</strong> 中，首先禁用柔和阴影，然后是附加光源的阴影，最后是主要阴影。<br>在 <strong>BiRP</strong> 中，将阴影切换到 <code>Hard Only</code> 模式，然后再将其完全禁用。</td></tr><tr><td style="text-align:left;"><strong>Shadow Cascades</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU/GPU</td><td style="text-align:left;">减少阴影级联的数量。减少 CPU 的 Draw Calls 和 GPU 负载。</td></tr><tr><td style="text-align:left;"><strong>Shadow Distance</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">缩短阴影绘制距离。</td></tr><tr><td style="text-align:left;"><strong>Shadow Resolution</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">降低阴影贴图 (Shadow Maps) 的分辨率。</td></tr><tr><td style="text-align:left;"><strong>Anti Aliasing</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">降低抗锯齿质量 (MSAA) 直至完全禁用。</td></tr><tr><td style="text-align:left;"><strong>LOD Bias</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">强制 Unity 在距离相机更近的位置切换到低多边形 LOD 模型。</td></tr><tr><td style="text-align:left;"><strong>Camera Clip</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">降低目标相机的 <code>Far Clip Plane</code> 参数，从渲染中剔除远处对象。</td></tr><tr><td style="text-align:left;"><strong>Layer Culling</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU</td><td style="text-align:left;">按比例缩小特定对象图层的剔除距离 (Culling Distance)。</td></tr><tr><td style="text-align:left;"><strong>Physics Step</strong></td><td style="text-align:left;"><code>BiRP</code> <code>URP</code></td><td style="text-align:left;">CPU</td><td style="text-align:left;">降低物理计算的频率。在浏览器出现繁重物理负载时拯救性能。</td></tr><tr><td style="text-align:left;"><strong>LUT</strong></td><td style="text-align:left;"><code>URP 专用</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">将颜色分级 (Color Grading LUT) 的大小减小到最低限度。</td></tr><tr><td style="text-align:left;"><strong>Mesh LOD Threshold</strong></td><td style="text-align:left;"><code>Unity 6+</code></td><td style="text-align:left;">GPU</td><td style="text-align:left;">更改在 Unity 6.2 中引入的 <code>meshLodThreshold</code> 参数，以进行激进的 LOD 切换。</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">对物理步长缩放器的注意事项</p><p>物理缩放器直接更改 <code>Time.fixedDeltaTime</code> 参数。如果角色控制器或游戏机制严格依赖于没有插值 (Interpolation) 的固定物理帧，对象移动在低质量级别可能会变得卡顿。</p></div><div class="tip custom-block"><p class="custom-block-title">重置缩放器设置</p><p>如果您尝试了缩放器参数（例如，修改了 <code>Min Bound</code> 或 <code>Max Level</code>）并希望将它们恢复为默认值，只需在 <em>Project Settings</em> 窗口中将开关关闭再打开即可。插件将使用基准设置自动重新创建该模块。</p></div><h2 id="剖析-分辨率缩放器-resolution-scaler" tabindex="-1">剖析：分辨率缩放器 (Resolution Scaler) <a class="header-anchor" href="#剖析-分辨率缩放器-resolution-scaler" aria-label="Permalink to &quot;剖析：分辨率缩放器 (Resolution Scaler)&quot;">​</a></h2><p>这是插件中最强大的工具，提供最高的 FPS 提升。它的操作会根据活动的管线发生巨大变化。</p><h3 id="在-urp-模式下-universal-render-pipeline" tabindex="-1">在 URP 模式下 (Universal Render Pipeline) <a class="header-anchor" href="#在-urp-模式下-universal-render-pipeline" aria-label="Permalink to &quot;在 URP 模式下 (Universal Render Pipeline)&quot;">​</a></h3><p>在 URP 中，缩放运行无缝。插件直接连接到 <code>UniversalRenderPipelineAsset</code> 内的 <code>renderScale</code> 属性。界面 (UI) 自动保持清晰，因为 URP 能够在缩放后的 3D 世界之上渲染 Canvas。</p><h3 id="在-birp-模式下-built-in-render-pipeline" tabindex="-1">在 BiRP 模式下 (Built-in Render Pipeline) <a class="header-anchor" href="#在-birp-模式下-built-in-render-pipeline" aria-label="Permalink to &quot;在 BiRP 模式下 (Built-in Render Pipeline)&quot;">​</a></h3><p>从历史上看，BiRP 缺乏一个可以在 WebGL 中运行而不会破坏界面或导致崩溃 (FBO Feedback Loop) 的内置渲染缩放 (Render Scale) 设置。WebAP 通过提供两种独占策略来解决这个问题。</p><h4 id="模式-1-nativebrowserscaling-原生浏览器缩放" tabindex="-1">模式 1：NativeBrowserScaling (原生浏览器缩放) <a class="header-anchor" href="#模式-1-nativebrowserscaling-原生浏览器缩放" aria-label="Permalink to &quot;模式 1：NativeBrowserScaling (原生浏览器缩放)&quot;">​</a></h4><p>插件通过原生循环欺骗（将其注入浏览器的 <code>devicePixelRatio</code> 参数）直接缩放 HTML <code>&lt;canvas&gt;</code> 元素。</p><ul><li><strong>优点：</strong> 最佳性能，GPU 端零开销。</li><li><strong>缺点：</strong> 游戏界面会随 3D 图形一起变得模糊。此模式仅在构建好的 WebGL 版本中运行（在 Unity 编辑器中看不到变化）。</li></ul><h4 id="模式-2-rendertexturescaling-渲染纹理缩放" tabindex="-1">模式 2：RenderTextureScaling (渲染纹理缩放) <a class="header-anchor" href="#模式-2-rendertexturescaling-渲染纹理缩放" aria-label="Permalink to &quot;模式 2：RenderTextureScaling (渲染纹理缩放)&quot;">​</a></h4><p>插件将目标相机的渲染重定向到压缩的共享纹理中，并使用隐藏的合成器相机 (Compositor Camera) 显示图像。</p><ul><li><strong>优点：</strong> 3D 世界被缩放，而 UI（文本、按钮）保持水晶般清晰。</li><li><strong>缺点：</strong> 由于 Blit 操作（将纹理复制到屏幕），会给 GPU 增加轻微负载。</li></ul><div class="info custom-block"><p class="custom-block-title">修复鼠标点击 (Raycasts)</p><p>当利用 RenderTextureScaling 时，虚拟屏幕坐标会被压缩。为确保在 3D 对象上的鼠标点击继续正常运行，插件自动将目标相机上的标准 <code>PhysicsRaycaster</code> 和 <code>Physics2DRaycaster</code> 组件替换为自定义 <code>WebScaledPhysicsRaycaster</code> 组件。射线的精度在任何缩放级别下都完美无缺。</p></div><h2 id="如何保持-ui-清晰度-对于-birp-rendertexturescaling" tabindex="-1">如何保持 UI 清晰度？（对于 BiRP RenderTextureScaling） <a class="header-anchor" href="#如何保持-ui-清晰度-对于-birp-rendertexturescaling" aria-label="Permalink to &quot;如何保持 UI 清晰度？（对于 BiRP RenderTextureScaling）&quot;">​</a></h2><p>为了在使用 RenderTextureScaling 缩放 3D 图形的同时保持界面清晰，您必须正确配置您的 Canvas。选择以下两个选项之一：</p><h3 id="选项-1-screen-space-overlay-推荐" tabindex="-1">选项 1：Screen Space - Overlay (推荐) <a class="header-anchor" href="#选项-1-screen-space-overlay-推荐" aria-label="Permalink to &quot;选项 1：Screen Space - Overlay (推荐)&quot;">​</a></h3><p>最简单和最可靠的方法。插件会自动处理所有工作。</p><ol><li>在场景层次结构中选择您的 <strong>Canvas</strong>。</li><li>在 Canvas 组件中，将 <strong>Render Mode</strong> 设置为 <code>Screen Space - Overlay</code>。<br><em>结果：</em> Unity 会以 100% 的原生分辨率将界面渲染在压缩后的 3D 世界之上。</li></ol><h3 id="选项-2-screen-space-camera-适用于复杂图层" tabindex="-1">选项 2：Screen Space - Camera (适用于复杂图层) <a class="header-anchor" href="#选项-2-screen-space-camera-适用于复杂图层" aria-label="Permalink to &quot;选项 2：Screen Space - Camera (适用于复杂图层)&quot;">​</a></h3><p>如果您需要混合 3D 模型、粒子和 UI，请使用此方法。您将需要跨两台相机分隔渲染。</p><ol><li><strong>主相机 (3D)：</strong> 确保在缩放器的 <code>Target Tags</code> 数组中指定了它的标签。在 <code>Culling Mask</code> 字段中，取消选中 <strong>UI</strong> 图层。将 <code>Depth</code> 设置为 <code>0</code>。</li><li><strong>UI 相机 (新增)：</strong> 创建一台新相机以渲染界面。<strong>不要</strong>将其标签添加到缩放器设置中。 <ul><li>将 <code>Clear Flags</code> 设置为 <code>Depth Only</code>（这样相机就不会擦除 3D 背景）。</li><li>专门将 <code>Culling Mask</code> 设置为 <strong>UI</strong> 图层。</li><li>将 <code>Depth</code> 设置为 <code>1</code>（高于主相机）。</li></ul></li><li><strong>Canvas 配置：</strong> 将 <strong>Render Mode</strong> 设置为 <code>Screen Space - Camera</code>，然后将新的 UI 相机拖入 <code>Render Camera</code> 插槽中。</li></ol>',28)])])}const P=t(r,[["render",o]]);export{h as __pageData,P as default};
